/**
 * Extract a section's body as raw text from AST nodes (no line-index math).
 * Each node emits its `raw` field; tasks include their subtask raws.
 */
export function sectionBodyText(section: Section): string {
  const lines: string[] = [];
  for (const node of section.body) {
    if (node.type === 'task') {
      const task = node as Task;
      lines.push(task.raw);
      for (const sub of task.subtasks) {
        lines.push(sub.raw);
      }
    } else {
